291	func (r *blockingCleanupRunner) Cleanup(ctx context.Context) (ExecutionCleanupSummary, error) {
292		atomic.AddInt32(&r.calls, 1)
293		active := atomic.AddInt32(&r.active, 1)
294		for {
295			prev := atomic.LoadInt32(&r.maxActive)
296			if active <= prev || atomic.CompareAndSwapInt32(&r.maxActive, prev, active) {
297				break
298			}
299		}
300		if r.started != nil {
301			select {
302			case <-r.started:
303			default:
304				close(r.started)
305			}
306		}
307		select {
308		case <-ctx.Done():
309		case <-r.release:
310		}
311		atomic.AddInt32(&r.active, -1)
312		return ExecutionCleanupSummary{}, nil
313	}
