 53	func (f *CommandFactory) runCleanup(cmd *cobra.Command, args []string) error {
 54		_ = args
 55		projectFlag, _ := cmd.Flags().GetString("project")
 56		apply, _ := cmd.Flags().GetBool("apply")
 57		asJSON, _ := cmd.Flags().GetBool("json")
 58	
 59		projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
 60		if projectRoot == "" {
 61			projectRoot = f.WorkingDir
 62		}
 63	
 64		mgr := agent.NewExecutionCleanupManager(projectRoot, &agent.RealGitOps{})
 65		mgr.DryRun = !apply
 66	
 67		summary, err := mgr.Cleanup(cmd.Context())
 68		if err != nil {
 69			return err
 70		}
 71	
 72		report := cleanupCommandReport{
 73			DryRun:                      !apply,
 74			ProjectRoot:                 summary.ProjectRoot,
 75			TempRoot:                    summary.TempRoot,
 76			ScannedTempDirs:             summary.ScannedTempDirs,
 77			ScannedEvidenceDirs:         summary.ScannedEvidenceDirs,
 78			CompleteEvidenceDirs:        summary.CompleteEvidenceDirs,
 79			RemovedUnregisteredTempDirs: summary.RemovedUnregisteredTempDirs,
 80			RemovedRegisteredWorktrees:  summary.RemovedRegisteredWorktrees,
 81			RemovedRunStateFiles:        summary.RemovedRunStateFiles,
 82			BytesReclaimed:              summary.BytesReclaimed,
 83			InodesReclaimed:             summary.InodesReclaimed,
 84			Warnings:                    append([]agent.ExecutionCleanupWarning(nil), summary.Warnings...),
 85			Observations:                append([]agent.ExecutionCleanupObservation(nil), summary.Observations...),
 86		}
 87		for _, issue := range summary.Issues {
 88			if issue.Blocking {
 89				report.BlockedErrors = append(report.BlockedErrors, issue)
 90			}
 91		}
 92		if report.Warnings == nil {
 93			report.Warnings = []agent.ExecutionCleanupWarning{}
 94		}
 95		if report.BlockedErrors == nil {
 96			report.BlockedErrors = []agent.ExecutionCleanupIssue{}
 97		}
 98		if report.Observations == nil {
 99			report.Observations = []agent.ExecutionCleanupObservation{}
100		}
101	
102		if asJSON {
103			enc := json.NewEncoder(cmd.OutOrStdout())
104			enc.SetIndent("", "  ")
105			return enc.Encode(report)
106		}
107	
108		out := cmd.OutOrStdout()
109		verb := "removed"
110		if report.DryRun {
111			verb = "would remove"
112		}
113		fmt.Fprintf(out, "cleanup: %s %d stale temp dir(s), %d registered worktree(s), %d run-state file(s)\n",
114			verb,
115			report.RemovedUnregisteredTempDirs,
116			report.RemovedRegisteredWorktrees,
117			report.RemovedRunStateFiles,
118		)
119		if report.BytesReclaimed > 0 || report.InodesReclaimed > 0 {
120			fmt.Fprintf(out, "cleanup: %s %d byte(s), %d inode(s)\n", verb, report.BytesReclaimed, report.InodesReclaimed)
121		}
122		if report.CompleteEvidenceDirs > 0 {
123			fmt.Fprintf(out, "cleanup: preserved %d complete evidence bundle(s)\n", report.CompleteEvidenceDirs)
124		}
125		for _, warning := range report.Warnings {
126			fmt.Fprintf(out, "warning: %s (%s): %s\n", warning.Path, warning.Class, warning.Message)
127		}
128		for _, issue := range report.BlockedErrors {
129			fmt.Fprintf(out, "blocked: %s (%s): %s\n", issue.Path, issue.Class, issue.Message)
130		}
131		if report.DryRun {
132			fmt.Fprintln(out, "run again with --apply to remove these resources")
133		}
134		return nil
135	}
